const stdout = items[0].json.stdout || "";
const sections = stdout.split("===");
const reports = [];

for (let i = 1; i < sections.length; i += 2) {
  const host = sections[i].trim();
  const content = sections[i+1] ? sections[i+1].trim() : "";

  if (content === "OFFLINE") {
    reports.push({ host, status: "OFFLINE" });
    continue;
  }

  const lines = content.split("\n");
  const dataLine = lines.find(line => line.includes("/") || line.includes("tmpfs") || line.match(/^\/dev\//) || line.split(/\s+/).length >= 6 && line !== lines[0]);
  if (dataLine) {
    const parts = dataLine.trim().split(/\s+/);
    if (parts.length >= 6) {
      reports.push({
        host,
        status: "ONLINE",
        filesystem: parts[0],
        size: parts[1],
        used: parts[2],
        available: parts[3],
        usage: parts[4],
        mount: parts[5]
      });
    } else {
      reports.push({ host, status: "PARSE_ERROR", raw: dataLine });
    }
  } else {
    reports.push({ host, status: "NO_DATA", raw: content });
  }
}

const warningThreshold = 80;
const criticalThreshold = 90;
let highestStatus = "Healthy";
let messageEmoji = "✅";

const lines = [];
lines.push("💾 **Homelab Disk Usage Report**");
lines.push("");
lines.push(`🕒 Time: ${new Date().toLocaleString("en-US", { timeZone: "America/Santo_Domingo" })}`);
lines.push("");

for (const report of reports) {
  if (report.status === "OFFLINE") {
    lines.push(`🚨 **${report.host}**: OFFLINE`);
    highestStatus = "Critical";
    messageEmoji = "🚨";
    continue;
  }

  if (report.status !== "ONLINE") {
    lines.push(`🚨 **${report.host}**: Unable to read disk stats`);
    highestStatus = "Critical";
    messageEmoji = "🚨";
    continue;
  }

  const usageVal = parseInt(report.usage.replace("%", ""), 10);
  let statusEmoji = "✅";

  if (usageVal >= criticalThreshold) {
    statusEmoji = "🚨";
    highestStatus = "Critical";
    messageEmoji = "🚨";
  } else if (usageVal >= warningThreshold) {
    statusEmoji = "⚠️";
    if (highestStatus !== "Critical") {
      highestStatus = "Warning";
      messageEmoji = "⚠️";
    }
  }

  lines.push(`${statusEmoji} **${report.host}**: ${report.usage} used (${report.used} / ${report.size}) — ${report.available} available`);
}

lines.push("");
lines.push("**Thresholds**");
lines.push(`- Warning: ${warningThreshold}% | Critical: ${criticalThreshold}%`);

return [
  {
    json: {
      content: lines.join("\n")
    }
  }
];
